import type { Metadata } from 'next'
import { notFound } from 'next/navigation'
import { Nav } from '@/components/nav'
import { PageHero } from '@/components/page-hero'
import { Footer } from '@/components/footer'
import { FadeInSection } from '@/components/ui/fade-in-section'
import { niches, getNicheById } from '@/lib/niches'

interface Props {
  params: { niche: string }
}

export async function generateStaticParams() {
  return niches.map((n) => ({ niche: n.id }))
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const niche = getNicheById(params.niche)
  if (!niche) return {}
  return {
    title: niche.heroTitle,
    description: niche.description,
  }
}

export default function NichePage({ params }: Props) {
  const niche = getNicheById(params.niche)
  if (!niche) notFound()

  return (
    <main>
      <Nav variant="chapter" />

      <PageHero
        chapterLabel={niche.sectorLabel}
        title={niche.heroTitle}
        description={niche.description}
      />

      {/* The Problem */}
      <section className="bg-fn3-warm-white border-b border-fn3-red-faint px-6 lg:px-12 py-20">
        <div className="max-w-[1400px] mx-auto">
          <FadeInSection>
            <p className="label-mono text-fn3-red-light mb-12">The Problem</p>
          </FadeInSection>
          <div className="grid grid-cols-1 lg:grid-cols-5 gap-12 lg:gap-20">
            <FadeInSection className="lg:col-span-2">
              <h2 className="font-display text-[clamp(24px,2.5vw,32px)] text-fn3-body leading-[1.1] tracking-tight">
                Where {niche.industry.toLowerCase()} operations break down.
              </h2>
            </FadeInSection>
            <div className="lg:col-span-3">
              {niche.painPoints.map((point, i) => (
                <FadeInSection key={i} delay={i * 0.07}>
                  <div className="flex gap-5 py-5 border-t border-fn3-red-faint last:border-b items-start">
                    <span className="label-mono text-fn3-red mt-0.5 flex-shrink-0 w-6">
                      {String(i + 1).padStart(2, '0')}
                    </span>
                    <p className="text-[15px] text-[#78716c] leading-[1.75]">{point}</p>
                  </div>
                </FadeInSection>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* How FN3 Fixes It */}
      <section className="bg-white border-b border-[#f3f4f6] px-6 lg:px-12 py-20">
        <div className="max-w-[1400px] mx-auto">
          <FadeInSection>
            <p className="label-mono text-fn3-red-light mb-10">How FN3 Fixes It</p>
          </FadeInSection>
          <div>
            {niche.solutions.map((solution, i) => (
              <FadeInSection key={i} delay={i * 0.07}>
                <div className="grid grid-cols-1 lg:grid-cols-[56px_1fr] gap-4 lg:gap-8 py-8 border-t border-[#f3f4f6] last:border-b items-start">
                  <span className="label-mono text-fn3-red-light">
                    {String(i + 1).padStart(2, '0')}
                  </span>
                  <p className="text-[15px] text-fn3-body leading-[1.75]">{solution}</p>
                </div>
              </FadeInSection>
            ))}
          </div>
        </div>
      </section>

      {/* Metrics */}
      <section className="bg-fn3-near-black px-6 lg:px-12 py-20">
        <div className="max-w-[1400px] mx-auto">
          <FadeInSection>
            <p className="label-mono text-fn3-dark-label mb-12">Results</p>
          </FadeInSection>
          <div className="grid grid-cols-1 sm:grid-cols-3">
            {niche.metrics.map((metric, i) => (
              <FadeInSection key={metric.label} delay={i * 0.1}>
                <div className={`${i > 0 ? 'pt-10 sm:pt-0 sm:pl-10 border-t sm:border-t-0 sm:border-l border-fn3-dark-border' : ''} ${i < niche.metrics.length - 1 ? 'pb-10 sm:pb-0 sm:pr-10' : ''}`}>
                  <p className="font-serif text-[56px] text-white font-normal leading-none mb-3">
                    {metric.value}
                  </p>
                  <p className="text-[14px] font-bold text-white mb-1">{metric.label}</p>
                  <p className="text-[12px] text-fn3-dark-text leading-[1.6]">{metric.description}</p>
                </div>
              </FadeInSection>
            ))}
          </div>
        </div>
      </section>

      {/* Testimonial */}
      {niche.testimonial && (
        <section className="bg-fn3-warm-white border-b border-fn3-red-faint px-6 lg:px-12 py-20">
          <div className="max-w-[1400px] mx-auto">
            <FadeInSection>
              <blockquote className="font-serif-italic text-[clamp(20px,2.5vw,28px)] text-fn3-body leading-[1.5] max-w-[720px] mb-8">
                &ldquo;{niche.testimonial.quote}&rdquo;
              </blockquote>
              <div className="flex items-center gap-4">
                <div className="w-8 h-px bg-fn3-red-faint" />
                <div>
                  <p className="text-[14px] font-bold text-fn3-body">{niche.testimonial.author}</p>
                  <p className="label-mono text-fn3-red-light mt-0.5">
                    {niche.testimonial.role}, {niche.testimonial.company}
                  </p>
                </div>
              </div>
            </FadeInSection>
          </div>
        </section>
      )}

      {/* CTA */}
      <section className="bg-white px-6 lg:px-12 py-20">
        <div className="max-w-[1400px] mx-auto">
          <FadeInSection>
            <p className="font-serif-italic text-[clamp(24px,3vw,40px)] text-fn3-body leading-[1.3] max-w-[560px] mb-10">
              Ready to bring operational intelligence into your {niche.industry.toLowerCase()} business?
            </p>
            <div className="flex flex-col sm:flex-row gap-6 items-start">
              <a
                href="/work-with-us"
                className="inline-block font-mono text-[11px] uppercase tracking-[0.12em] text-white bg-fn3-red px-8 py-4 hover:bg-fn3-body transition-colors duration-150"
              >
                {niche.cta.primary}
              </a>
              <a
                href="/how-we-work"
                className="inline-block font-mono text-[11px] uppercase tracking-[0.12em] text-fn3-red border-b border-fn3-red pb-px hover:text-fn3-body hover:border-fn3-body transition-colors duration-150 mt-4 sm:mt-[18px]"
              >
                See How We Work →
              </a>
            </div>
          </FadeInSection>
        </div>
      </section>

      <Footer />
    </main>
  )
}
